import type { Command } from "commander";
import { findSeedsDir, isInsideWorktree, projectRootFromSeedsDir } from "../config.ts";
import { outputJson, printWarning } from "../output.ts";
import { SEEDS_DIR_NAME } from "../types.ts";

function spawnSync(
	cmd: string[],
	cwd: string,
): { stdout: string; stderr: string; exitCode: number } {
	const result = Bun.spawnSync(cmd, { cwd, stdout: "pipe", stderr: "pipe" });
	const stdout = new TextDecoder().decode(result.stdout);
	const stderr = new TextDecoder().decode(result.stderr);
	return { stdout, stderr, exitCode: result.exitCode ?? 0 };
}

export async function run(args: string[], seedsDir?: string): Promise<void> {
	const jsonMode = args.includes("--json");
	const statusOnly = args.includes("--status");
	const dryRun = args.includes("--dry-run");

	const dir = seedsDir ?? (await findSeedsDir());
	const projectRoot = projectRootFromSeedsDir(dir);

	// Worktree guard: skip commit when running from a worktree
	if (!seedsDir && isInsideWorktree(process.cwd())) {
		const msg = "Inside a git worktree — skipping commit. Issues are stored in the main repo.";
		if (jsonMode) {
			await outputJson({
				success: true,
				command: "sync",
				committed: false,
				worktree: true,
				message: msg,
			});
		} else {
			printWarning(msg);
		}
		return;
	}

	const statusResult = spawnSync(
		["git", "-C", projectRoot, "status", "--porcelain", `${SEEDS_DIR_NAME}/`],
		projectRoot,
	);

	const changed = statusResult.stdout.trim();

	if (statusOnly) {
		if (jsonMode) {
			await outputJson({ success: true, command: "sync", hasChanges: !!changed, changes: changed });
		} else {
			if (changed) {
				console.log("Uncommitted .seeds/ changes:");
				console.log(changed);
			} else {
				console.log("No uncommitted .seeds/ changes.");
			}
		}
		return;
	}

	if (!changed) {
		if (jsonMode) {
			await outputJson({
				success: true,
				command: "sync",
				committed: false,
				message: "Nothing to commit",
			});
		} else {
			console.log("No changes to commit.");
		}
		return;
	}

	if (dryRun) {
		const date = new Date().toISOString().slice(0, 10);
		const msg = `seeds: sync ${date}`;
		if (jsonMode) {
			await outputJson({
				success: true,
				command: "sync",
				dryRun: true,
				wouldCommit: true,
				message: msg,
				changes: changed,
			});
		} else {
			console.log("Dry run — would commit:");
			console.log(changed);
			console.log(`Commit message: ${msg}`);
		}
		return;
	}

	// Stage
	const addResult = spawnSync(["git", "-C", projectRoot, "add", `${SEEDS_DIR_NAME}/`], projectRoot);
	if (addResult.exitCode !== 0) {
		throw new Error(`git add failed: ${addResult.stderr}`);
	}

	// Commit
	const date = new Date().toISOString().slice(0, 10);
	const msg = `seeds: sync ${date}`;
	const commitResult = spawnSync(["git", "-C", projectRoot, "commit", "-m", msg], projectRoot);
	if (commitResult.exitCode !== 0) {
		throw new Error(`git commit failed: ${commitResult.stderr}`);
	}

	if (jsonMode) {
		await outputJson({ success: true, command: "sync", committed: true, message: msg });
	} else {
		console.log(`Committed: ${msg}`);
	}
}

export function register(program: Command): void {
	program
		.command("sync")
		.description("Stage and commit .seeds/ changes")
		.option("--status", "Check status without committing")
		.option("--dry-run", "Show what would be committed without committing")
		.option("--json", "Output as JSON")
		.action(async (opts: { status?: boolean; dryRun?: boolean; json?: boolean }) => {
			const args: string[] = [];
			if (opts.status) args.push("--status");
			if (opts.dryRun) args.push("--dry-run");
			if (opts.json) args.push("--json");
			await run(args);
		});
}

import chalk from "chalk";
import { stripAnsi } from "./format.ts";
import type { Issue } from "./types.ts";
import { PRIORITY_LABELS } from "./types.ts";

// Forest palette
export const brand = chalk.rgb(124, 179, 66);
export const accent = chalk.rgb(255, 183, 77);
export const muted = chalk.rgb(120, 120, 110);

let _quiet = false;

export function setQuiet(v: boolean): void {
	_quiet = v;
}

export async function outputJson(data: unknown): Promise<void> {
	await Bun.write(Bun.stdout, `${JSON.stringify(data, null, 2)}\n`);
}

export function printSuccess(msg: string): void {
	if (_quiet) return;
	console.log(`${brand("✓")} ${brand(msg)}`);
}

export function printError(msg: string): void {
	console.error(`${chalk.red("✗")} ${msg}`);
}

export function printWarning(msg: string): void {
	if (_quiet) return;
	console.error(`${chalk.yellow("!")} ${msg}`);
}

// An issue is *effectively* blocked when at least one entry in `blockedBy`
// references a still-open issue. When `closedBlockerIds` is omitted, fall back
// to the legacy length-based heuristic for callers that haven't threaded the
// set through yet.
function isEffectivelyBlocked(issue: Issue, closedBlockerIds?: Set<string>): boolean {
	const blockers = issue.blockedBy ?? [];
	if (blockers.length === 0) return false;
	if (!closedBlockerIds) return true;
	return blockers.some((bid) => !closedBlockerIds.has(bid));
}

export function formatIssueOneLine(issue: Issue, closedBlockerIds?: Set<string>): string {
	const isBlocked = isEffectivelyBlocked(issue, closedBlockerIds);
	const statusIcon =
		issue.status === "closed"
			? muted("x")
			: issue.status === "in_progress"
				? chalk.cyan(">")
				: isBlocked
					? chalk.yellow("!")
					: brand("-");
	const priorityLabel = PRIORITY_LABELS[issue.priority] ?? String(issue.priority);
	const assignee = issue.assignee ? ` · ${muted(`@${issue.assignee}`)}` : "";
	const blocked = isBlocked ? ` ${chalk.yellow("[blocked]")}` : "";
	const labelStr = issue.labels?.length ? ` ${muted(`{${issue.labels.join(", ")}}`)}` : "";
	return `${statusIcon} ${accent.bold(issue.id)} · ${issue.title}   ${muted(`[${priorityLabel} · ${issue.type}]`)}${assignee}${blocked}${labelStr}`;
}

export function formatIssueOneLineCompact(issue: Issue, closedBlockerIds?: Set<string>): string {
	const priorityLabel = PRIORITY_LABELS[issue.priority] ?? String(issue.priority);
	const isBlocked = isEffectivelyBlocked(issue, closedBlockerIds);
	const status = isBlocked ? "blocked" : issue.status;
	return `${issue.id} ${priorityLabel} ${status} ${issue.title}`;
}

export function printIssueOneLine(issue: Issue, closedBlockerIds?: Set<string>): void {
	if (_quiet) return;
	console.log(formatIssueOneLine(issue, closedBlockerIds));
}

// Render Issue.extensions as a single "Extensions: key=value ..." line.
// Each value is JSON-encoded so the rendering round-trips unambiguously
// (strings stay quoted; objects/arrays/null print as JSON literals).
// Returns null when extensions is missing or has no own keys.
function formatExtensionsLine(ext: Record<string, unknown> | undefined): string | null {
	if (!ext) return null;
	const keys = Object.keys(ext);
	if (keys.length === 0) return null;
	const pairs = keys.map((k) => `${accent(k)}=${muted(JSON.stringify(ext[k]))}`);
	return `Extensions: ${pairs.join(" ")}`;
}

export function formatIssueFull(issue: Issue): string {
	const statusColor =
		issue.status === "closed" ? muted : issue.status === "in_progress" ? chalk.cyan : brand;
	const priorityLabel = PRIORITY_LABELS[issue.priority] ?? String(issue.priority);

	const lines: string[] = [];
	lines.push(`${accent.bold(issue.id)}  ${statusColor(issue.status)}`);
	lines.push(`Title:    ${issue.title}`);
	lines.push(`Type:     ${muted(issue.type)}   Priority: ${muted(priorityLabel)}`);
	if (issue.assignee) lines.push(`Assignee: ${issue.assignee}`);
	if (issue.labels?.length)
		lines.push(`Labels:   ${issue.labels.map((l) => accent(l)).join(", ")}`);
	const extLine = formatExtensionsLine(issue.extensions);
	if (extLine) lines.push(extLine);
	if (issue.description) lines.push(`\n${issue.description}`);
	if (issue.blockedBy?.length)
		lines.push(`Blocked by: ${issue.blockedBy.map((id) => accent(id)).join(", ")}`);
	if (issue.blocks?.length)
		lines.push(`Blocks:     ${issue.blocks.map((id) => accent(id)).join(", ")}`);
	if (issue.convoy) lines.push(`Convoy:   ${muted(issue.convoy)}`);
	if (issue.closeReason) lines.push(`Reason:   ${issue.closeReason}`);
	lines.push(`Created:  ${muted(issue.createdAt)}`);
	lines.push(`Updated:  ${muted(issue.updatedAt)}`);
	if (issue.closedAt) lines.push(`Closed:   ${muted(issue.closedAt)}`);
	return lines.join("\n");
}

export function printIssueFull(issue: Issue): void {
	if (_quiet) return;
	console.log(formatIssueFull(issue));
}

export function plain(s: string): string {
	return stripAnsi(s);
}

import { afterEach, beforeEach, describe, expect, test } from "bun:test";
import { mkdirSync, realpathSync, writeFileSync } from "node:fs";
import { mkdtemp, rm } from "node:fs/promises";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { run } from "./sync";

function git(args: string[], cwd: string): void {
	const result = Bun.spawnSync(["git", ...args], { cwd, stdout: "pipe", stderr: "pipe" });
	if ((result.exitCode ?? 0) !== 0) {
		const stderr = new TextDecoder().decode(result.stderr);
		throw new Error(`git ${args.join(" ")} failed: ${stderr}`);
	}
}

function initSeedsDir(root: string): void {
	const seedsDir = join(root, ".seeds");
	mkdirSync(seedsDir, { recursive: true });
	writeFileSync(join(seedsDir, "config.yaml"), 'project: "test"\nversion: "1"\n');
	writeFileSync(join(seedsDir, "issues.jsonl"), "");
	writeFileSync(join(seedsDir, ".gitignore"), "*.lock\n");
}

let tmpDir: string;

beforeEach(async () => {
	tmpDir = realpathSync(await mkdtemp(join(tmpdir(), "seeds-sync-test-")));
});

afterEach(async () => {
	await rm(tmpDir, { recursive: true, force: true });
});

describe("sync — worktree guard", () => {
	test("warns and no-ops inside a worktree", async () => {
		const mainRepo = join(tmpDir, "main");
		mkdirSync(mainRepo);
		git(["init"], mainRepo);
		git(["config", "user.email", "test@test.com"], mainRepo);
		git(["config", "user.name", "Test"], mainRepo);
		initSeedsDir(mainRepo);
		git(["add", "."], mainRepo);
		git(["commit", "-m", "init"], mainRepo);

		const wtDir = join(tmpDir, "wt");
		git(["worktree", "add", wtDir, "-b", "wt-branch"], mainRepo);

		// Capture console output. printWarning routes to stderr, so capture
		// both streams and assert the warning lands on stderr.
		const logs: string[] = [];
		const errs: string[] = [];
		const origLog = console.log;
		const origErr = console.error;
		console.log = (...args: unknown[]) => {
			logs.push(args.map(String).join(" "));
		};
		console.error = (...args: unknown[]) => {
			errs.push(args.map(String).join(" "));
		};

		const origCwd = process.cwd();
		process.chdir(wtDir);
		try {
			await run([]);
		} finally {
			process.chdir(origCwd);
			console.log = origLog;
			console.error = origErr;
		}

		expect(errs.some((l) => l.includes("worktree"))).toBe(true);
		expect(logs.some((l) => l.includes("worktree"))).toBe(false);
	});

	test("sd sync --json returns worktree: true inside a worktree", async () => {
		const mainRepo = join(tmpDir, "main");
		mkdirSync(mainRepo);
		git(["init"], mainRepo);
		git(["config", "user.email", "test@test.com"], mainRepo);
		git(["config", "user.name", "Test"], mainRepo);
		initSeedsDir(mainRepo);
		git(["add", "."], mainRepo);
		git(["commit", "-m", "init"], mainRepo);

		const wtDir = join(tmpDir, "wt");
		git(["worktree", "add", wtDir, "-b", "wt-branch"], mainRepo);

		// Worktree-guard branch only fires when sync is invoked as the top-
		// level CLI (no explicit seedsDir arg). The in-process harness passes
		// a resolved seedsDir which bypasses the guard, so this test stays
		// subprocess-based to exercise the real CLI codepath.
		const result = Bun.spawnSync(
			["bun", "run", join(import.meta.dir, "..", "index.ts"), "sync", "--json"],
			{
				cwd: wtDir,
				stdout: "pipe",
				stderr: "pipe",
			},
		);

		const output = JSON.parse(new TextDecoder().decode(result.stdout));
		expect(output.worktree).toBe(true);
		expect(output.committed).toBe(false);
		expect(output.success).toBe(true);
	});

	test("sd sync commits normally from main repo", async () => {
		const mainRepo = join(tmpDir, "main");
		mkdirSync(mainRepo);
		git(["init"], mainRepo);
		git(["config", "user.email", "test@test.com"], mainRepo);
		git(["config", "user.name", "Test"], mainRepo);
		initSeedsDir(mainRepo);
		git(["add", "."], mainRepo);
		git(["commit", "-m", "init"], mainRepo);

		// Create a new issue to have uncommitted changes
		const issuesPath = join(mainRepo, ".seeds", "issues.jsonl");
		writeFileSync(
			issuesPath,
			'{"id":"test-0001","title":"Test","status":"open","type":"task","priority":2,"createdAt":"2026-01-01T00:00:00Z","updatedAt":"2026-01-01T00:00:00Z"}\n',
		);

		const logs: string[] = [];
		const origLog = console.log;
		console.log = (...args: unknown[]) => {
			logs.push(args.map(String).join(" "));
		};

		const origCwd = process.cwd();
		process.chdir(mainRepo);
		try {
			await run([]);
		} finally {
			process.chdir(origCwd);
			console.log = origLog;
		}

		expect(logs.some((l) => l.includes("Committed"))).toBe(true);
	});
});

